87	Card	45	1	2026-02-24 12:10:23.168373+00	{"description":"Значения всех метрик для одного варианта","archived":false,"collection_position":null,"source_card_id":null,"table_id":null,"embedding_type":null,"dependency_analysis_version":0,"card_schema":23,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"Значения всех метрик для конкретного варианта","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"lib/type":"mbql/query","database":2,"stages":[{"native":"SELECT\\n      m.key           AS metric_key,\\n      m.name          AS metric_name,\\n      ms.variant_name AS variant_name,\\n      ms.is_control,\\n      ms.value,\\n      ms.value_num,\\n      ms.value_denom\\n  FROM experiment_metrics em\\n  JOIN metrics m ON m.id = em.metric_id\\n  join experiment_versions ev on ev.name = {{experiment_name}}\\n  CROSS JOIN LATERAL fn_metric_summary(\\n      em.experiment_id,\\n      m.key,\\n      {{date_from}}::timestamptz,\\n      {{date_to}}::timestamptz,\\n\\t  {{payload_str_name}}::text,\\n\\t  {{payload_str_value}}::text\\n  ) ms\\n  WHERE em.experiment_id = ev.experiment_id and variant_name = {{variant_name}}\\n  ORDER BY m.name, ms.is_control DESC\\n\\n","lib/type":"mbql.stage/native","template-tags":{"date_from":{"name":"date_from","id":"078ac93a-896a-4780-bb84-0ea843e2ae91","type":"text","display-name":"Date From"},"date_to":{"name":"date_to","id":"6aa4fc7d-5b30-4c12-b124-46e8a98b978e","type":"text","display-name":"Date To"},"variant_name":{"name":"variant_name","id":"e76adfb4-4d9c-4f6d-a0ab-fbaf2720e53c","type":"text","display-name":"Variant Name"},"experiment_name":{"name":"experiment_name","id":"bf30414d-296c-4341-8831-6c0c40b3da4c","type":"text","display-name":"Experiment Name"},"payload_str_name":{"display-name":"Payload Str Name","id":"3cafe9a4-1d74-4103-8de2-5365c912832b","type":"text","name":"payload_str_name","default":"''"},"payload_str_value":{"display-name":"Payload Str Value","type":"te