6	Card	39	1	2026-02-21 09:50:39.325778+00	{"description":"Динамика всех метрик для выбранного варианта","archived":false,"collection_position":null,"source_card_id":null,"table_id":null,"embedding_type":null,"dependency_analysis_version":0,"card_schema":23,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"Динамика метрик конкретного варианта","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"lib/type":"mbql/query","database":2,"stages":[{"lib/type":"mbql.stage/native","native":"  SELECT                                                                                                                                                                       \\n      m.key           AS metric_key,                                                                                                                                           \\n      m.name          AS metric_name,\\n      ts.bucket_start,\\n      ts.bucket_end,\\n      ts.value\\n  FROM experiment_metrics em\\n  JOIN metrics m ON m.id = em.metric_id\\n  CROSS JOIN LATERAL fn_metric_timeseries(\\n      em.experiment_id,\\n      m.key,\\n      {{date_from}}::timestamptz,\\n      {{date_to}}::timestamptz,\\n      {{granularity}}\\n  ) ts\\n  WHERE em.experiment_id = {{experiment_id}}\\n    AND ts.variant_name  = {{variant_name}}\\n  ORDER BY m.name, ts.bucket_start","template-tags":{"date_from":{"type":"text","name":"date_from","id":"cb488906-3752-49ff-96bb-e98bf939509d","display-name":"Date From"},"date_to":{"type":"text","name":"date_to","id":"d98d3477-ac23-4f60-b3c1-f77115bb3cc3","display-name":"Date To"},"experiment_id":{"type":"text","name":"experiment_id","id":"4ddc1fc9-7a42-4bc8-8fe1-8a89f2c0cbcd","display-name":"Experiment ID"},"granularity":{"name":"granularity","id":"0f04e55f-f06e-4030-9bdc-cf08ad388eda","type":"text","display-name":"Granularity"},"variant_name":{"name":"variant_name","id":"233fc72f-06da-48fd-bcec-af3de3a52b2e","type":"text"