3	Card	38	1	2026-02-21 09:37:04.602577+00	{"description":"Количество уникальных субьектов в каждом варианте","archived":false,"collection_position":null,"source_card_id":null,"table_id":null,"embedding_type":null,"dependency_analysis_version":0,"card_schema":23,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"количество уникальных субьектов","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"lib/type":"mbql/query","database":2,"stages":[{"native":"  SELECT\\n      v.name          AS variant_name,\\n      v.is_control,\\n      count(d.id)              AS decisions_count,\\n      count(DISTINCT d.subject_id) AS unique_subjects\\n  FROM variants v\\n  LEFT JOIN decisions d ON d.variant_id = v.id\\n  WHERE d.experiment_id = {{experiment_id}}\\n  GROUP BY v.name, v.is_control\\n  ORDER BY v.is_control DESC, v.name","lib/type":"mbql.stage/native","template-tags":{"experiment_id":{"type":"text","name":"experiment_id","id":"12ab50f4-dc3b-4f16-8921-4881e972bffe","display-name":"Experiment ID"}}}]},"parameter_mappings":[],"display":"bar","archived_directly":false,"collection_preview":true,"visualization_settings":{"graph.series_order":null,"graph.series_order_dimension":null,"graph.dimensions":["variant_name"],"series_settings":{"unique_subjects":{"color":"#51528D"}},"graph.x_axis.scale":"ordinal","graph.metrics":["unique_subjects"]},"parameters":[{"id":"12ab50f4-dc3b-4f16-8921-4881e972bffe","type":"string/=","target":["variable",["template-tag","experiment_id"]],"name":"Experiment ID","slug":"experiment_id","isMultiSelect":false}],"dashboard_id":2}	f	t	\N	f	v0.58.7 (85988ba)
11	Card	40	1	2026-02-21 09:59:15.308657+00	{"description":"Процентное соотношение статусов пришедших событий","archived":false,"collection_position":null,"source_card_id":null,"table_id":null,"embedding_type":null,"dependency_analysis_version":0,"card_schema":23,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"Статусы событий","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"lib/type":"mbql/query","database":2,"stages":[{"native":"  SELECT\\n      er.status,\\n      count(*)                                                        AS cnt,\\n      round(100.0 * count(*) / sum(count(*)) OVER (), 1)             AS pct\\n  FROM events_raw er\\n  JOIN decisions d ON er.decision_id = d.id\\n  JOIN variants  v ON d.variant_id   = v.id\\n  WHERE d.experiment_id = {{experiment_id}}\\n    AND er.occurred_at BETWEEN {{date_from}}::timestamptz\\n                           AND {{date_to}}::timestamptz\\n  GROUP BY er.status\\n  ORDER BY cnt DESC","lib/type":"mbql.stage/native","template-tags":{"experiment_id":{"type":"text","name":"experiment_id","id":"f40eb54a-1e86-4724-8769-ba2e78250d3d","display-name":"Experiment ID"},"date_from":{"type":"text","name":"date_from","id":"2d70f1dd-69ad-4fdb-b88e-1dfb6da7be14","display-name":"Date From"},"date_to":{"type":"text","name":"date_to","id":"4ee632a6-6501-4a7a-ba0c-5dbc71cced08","display-name":"Date To"}}}]},"parameter_mappings":[],"display":"pie","archived_directly":false,"collection_preview":true,"visualization_settings":{"pie.metric":"cnt","pie.dimension":["status"]},"parameters":[{"id":"f40eb54a-1e86-4724-8769-ba2e78250d3d","type":"string/=","target":["variable",["template-tag","experiment_id"]],"name":"Experiment ID","slug":"experiment_id","isMultiSelect":false},{"id":"2d70f1dd-69ad-4fdb-b88e-1dfb6da7be14","type":"string/=","target":["variable",["template-tag","date_from"]],"name":"Date From","slug":"date_from","isMultiSelect":false},{"id":"4ee632a6-6501-4a7a-ba0c