22	Card	43	1	2026-02-21 10:27:54.999243+00	{"description":"Процент перекоса трафика на каждом варианте","archived":false,"collection_position":null,"source_card_id":null,"table_id":null,"embedding_type":null,"dependency_analysis_version":0,"card_schema":23,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"Перекос трафика по вариантам в процентах","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"lib/type":"mbql/query","database":2,"stages":[{"lib/type":"mbql.stage/native","native":"SELECT\\n      v.name                                                                  AS variant_name,\\n      v.is_control,\\n      round(100.0 * v.weight / sum(v.weight) OVER (), 2)                     AS expected_percentage,\\n      count(d.id)                                                             AS actual_decisions,\\n      round(\\n          100.0 * count(d.id) / NULLIF(sum(count(d.id)) OVER (), 0), 2\\n      )                                                                       AS actual_percentage,\\n      round(\\n          100.0 * count(d.id) / NULLIF(sum(count(d.id)) OVER (), 0), 2\\n      ) - round(100.0 * v.weight / sum(v.weight) OVER (), 2)                 AS skew_percentage\\n  FROM variants v\\n  LEFT JOIN decisions d ON d.variant_id = v.id\\n  WHERE d.experiment_id = {{experiment_id}}\\n  GROUP BY v.id, v.name, v.is_control, v.weight\\n  ORDER BY v.is_control DESC, v.name","template-tags":{"experiment_id":{"id":"4fd362bd-d604-41cf-8a1f-80a034e998d1","type":"text","name":"experiment_id","display-name":"Experiment ID"}}}]},"parameter_mappings":[],"display":"bar","archived_directly":false,"collection_preview":true,"visualization_settings":{"graph.x_axis.scale":"ordinal","series_settings":{"expected_percentage":{"color":"#227FD2"},"actual_percentage":{"color":"#51528D"},"skew_percentage":{"color":"#E75454"}},"graph.dimensions":["variant_name"],"graph.series_order_dimension":null,"graph.series_order":null,"graph.metrics":["skew_percentage"]},"parameters":[{"id":"4fd362bd-d604-41cf-8a1f-80a034e998d1","type":"string/=","target":["variable",["template-tag","experiment_id"]],"name":"Experiment ID","slug":"experiment_id","isMultiSelect":false}],"dashboard_id":2}	f	t	\N	f	v0.58.7 (85988ba)
