58	Card	38	1	2026-02-24 10:09:48.747401+00	{"description":"Количество уникальных субьектов в каждом варианте","archived":false,"collection_position":null,"source_card_id":null,"table_id":null,"embedding_type":null,"dependency_analysis_version":0,"card_schema":23,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"количество уникальных субьектов","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"lib/type":"mbql/query","database":2,"stages":[{"native":"  SELECT\\n      v.name          AS variant_name,\\n      v.is_control,\\n      count(d.id)              AS decisions_count,\\n      count(DISTINCT d.subject_id) AS unique_subjects\\n  FROM variants v\\n  join experiment_versions ev on ev.name = {{experiment_name}}\\n  LEFT JOIN decisions d ON d.variant_id = v.id\\n  WHERE d.experiment_id = ev.experiment_id\\n  GROUP BY v.name, v.is_control\\n  ORDER BY v.is_control DESC, v.name","lib/type":"mbql.stage/native","template-tags":{"experiment_name":{"name":"experiment_name","id":"a8d23cd5-6d1c-4099-9456-d2488cba0d2a","type":"text","display-name":"Experiment Name"}}}]},"parameter_mappings":[],"display":"bar","archived_directly":false,"collection_preview":true,"visualization_settings":{"graph.series_order":null,"graph.series_order_dimension":null,"graph.dimensions":["variant_name"],"series_settings":{"unique_subjects":{"color":"#51528D"}},"graph.x_axis.scale":"ordinal","graph.metrics":["unique_subjects"]},"parameters":[{"id":"a8d23cd5-6d1c-4099-9456-d2488cba0d2a","type":"string/=","target":["variable",["template-tag","experiment_name"]],"name":"Experiment Name","slug":"experiment_name","isMultiSelect":false}],"dashboard_id":2}	f	f	\N	t	v0.58.7.1 (465943a)
60	Card	40	1	2026-02-24 10:53:11.076123+00	{"description":"Процентное соотношение статусов пришедших событий","archived":false,"collection_position":null,"source_card_id":null,"table_id":null,"embedding_type":null,"dependency_analysis_version":0,"card_schema":23,"database_id":2,"enable_embedding":false,"collection_id":null,"query_type":"native","name":"Статусы событий","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"lib/type":"mbql/query","database":2,"stages":[{"native":"  SELECT\\n      er.status,\\n      count(*)                                                        AS cnt,\\n      round(100.0 * count(*) / sum(count(*)) OVER (), 1)             AS pct\\n  FROM events_raw er\\n  JOIN decisions d ON er.decision_id = d.id\\n  JOIN variants  v ON d.variant_id   = v.id\\n  join experiment_versions ev on ev.name = {{experiment_name}}\\n  WHERE d.experiment_id = ev.experiment_id\\n    AND er.occurred_at BETWEEN {{date_from}}::timestamptz\\n                           AND {{date_to}}::timestamptz\\n  GROUP BY er.status\\n  ORDER BY cnt DESC","lib/type":"mbql.stage/native","template-tags":{"date_from":{"name":"date_from","id":"2d70f1dd-69ad-4fdb-b88e-1dfb6da7be14","type":"text","display-name":"Date From"},"date_to":{"name":"date_to","id":"4ee632a6-6501-4a7a-ba0c-5dbc71cced08","type":"text","display-name":"Date To"},"experiment_name":{"id":"ba960235-8181-401b-a2bc-ceae5866b1c1","type":"text","name":"experiment_name","display-name":"Experiment Name"}}}]},"parameter_mappings":[],"display":"pie","archived_directly":false,"collection_preview":true,"visualization_settings":{"pie.metric":"cnt","pie.dimension":["status"]},"parameters":[{"id":"2d70f1dd-69ad-4fdb-b88e-1dfb6da7be14","type":"string/=","target":["variable",["template-tag","date_from"]],"name":"Date From","slug":"date_from","isMultiSelect":false},{"id":"4ee632a6-6501-4a7a-ba0c-5dbc71cced08","type":"string/=","target":["variable",["template-tag","date_to"]],"name":"Date To","slug":"date_to","